patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index f29fb6780253..79a7bb0add87 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -13359,8 +13359,12 @@ InstructionCost BoUpSLP::getSpillCost() {
       if (Op->isGather()) {
         assert(Entry->getOpcode() == Instruction::PHI &&
                "Expected phi node only.");
-        OpParent = cast<PHINode>(Entry->getMainOp())
-                       ->getIncomingBlock(Op->UserTreeIndex.EdgeIdx);
+        auto *Phi = cast<PHINode>(Entry->getMainOp());
+        if (Op->UserTreeIndex.EdgeIdx >= Phi->getNumIncomingValues())
+          continue;
+        OpParent = Phi->getIncomingBlock(Op->UserTreeIndex.EdgeIdx);
+        if (!OpParent)
+          continue;
         OpLastInst = OpParent->getTerminator();
         for (Value *V : Op->Scalars) {
           auto *Inst = dyn_cast<Instruction>(V);

